<?php
namespace Tests\Feature\Admin\Content;use App\Models\CharacterClass;use App\Models\CharacterTemplate;use App\Models\User;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Http\UploadedFile;use Illuminate\Support\Facades\Storage;use Tests\TestCase;
class CharacterTemplateAdminTest extends TestCase{use RefreshDatabase;private $admin;protected function setUp():void{parent::setUp();Storage::fake('public');config(['game_admin.emails'=>['admin@example.test']]);$this->admin=User::factory()->create(['email'=>'admin@example.test']);}private function payload($overrides=[]){return array_merge(['code'=>'human_warrior','name'=>'Guerrero humano','description'=>'Plantilla inicial','character_class_id'=>CharacterClass::where('code','adventurer')->firstOrFail()->id,'presentation_gender'=>'male','body_type'=>'human_male_01','status'=>'inactive','sort_order'=>1,'base_max_health'=>120,'base_attack'=>14,'base_defense'=>8,'base_accuracy'=>80,'base_evasion'=>5,'base_critical_rate'=>'6.25'],$overrides);}public function test_access_and_crud_with_visual_and_status_actions(){$this->get(route('admin.content.character-templates.index'))->assertRedirect('/login');$this->actingAs(User::factory()->create())->get(route('admin.content.character-templates.index'))->assertForbidden();$this->actingAs($this->admin)->post(route('admin.content.character-templates.store'),$this->payload(['image'=>UploadedFile::fake()->image('body.png',512,768)]))->assertRedirect();$template=CharacterTemplate::where('code','human_warrior')->firstOrFail();$this->get(route('admin.content.character-templates.index'))->assertOk()->assertSee('human_male_01');$this->patch(route('admin.content.character-templates.activate',$template))->assertRedirect();$this->assertSame('active',$template->fresh()->status);$this->delete(route('admin.content.character-templates.image.destroy',$template))->assertSessionHasErrors('content');$this->patch(route('admin.content.character-templates.deactivate',$template));$this->delete(route('admin.content.character-templates.image.destroy',$template))->assertRedirect();$this->assertFalse($template->mediaAssets()->exists());}public function test_validation_is_spanish_and_bad_ratio_is_rejected(){$this->actingAs($this->admin)->post(route('admin.content.character-templates.store'),$this->payload(['body_type'=>'Human Male','image'=>UploadedFile::fake()->image('square.png',512,512)]))->assertSessionHasErrors('body_type');$this->post(route('admin.content.character-templates.store'),$this->payload(['code'=>'ratio_bad','image'=>UploadedFile::fake()->image('square.png',512,512)]))->assertSessionHasErrors('image');}}
